import{_ as e,c as t,o as p,ae as r}from"./chunks/framework.BvcDoAct.js";const l=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2/PART2/10.md","filePath":"zh-cn/Management2/PART2/10.md"}'),o={name:"zh-cn/Management2/PART2/10.md"};function n(S,a,i,s,h,G){return p(),t("div",null,[...a[0]||(a[0]=[r('<p>► 2023/04</p><h2 id="与bmsg产生共鸣的伙伴举办派对" tabindex="-1">与BMSG产生共鸣的伙伴举办派对 <a class="header-anchor" href="#与bmsg产生共鸣的伙伴举办派对" aria-label="Permalink to &quot;与BMSG产生共鸣的伙伴举办派对&quot;">​</a></h2><p>#G&amp;G #关系构建 #伙伴打造</p><h3 id="「希望能够在商业与人生层面-都去倡导-正确地去做梦-朝着它正确地努力-正确地增加伙伴-并且正确地去实现它」" tabindex="-1">「希望能够在商业与人生层面，都去倡导：正确地去做梦，朝着它正确地努力，正确地增加伙伴，并且正确地去实现它」 <a class="header-anchor" href="#「希望能够在商业与人生层面-都去倡导-正确地去做梦-朝着它正确地努力-正确地增加伙伴-并且正确地去实现它」" aria-label="Permalink to &quot;「希望能够在商业与人生层面，都去倡导：正确地去做梦，朝着它正确地努力，正确地增加伙伴，并且正确地去实现它」&quot;">​</a></h3><p><strong>4月上旬，BMSG举办了一场邀请相关人士参加的派对“Greeting&amp;Gathering”（以下简称“G&amp;G”）。这是在公司迈入第三期中段之际，以向各合作方表达感谢与问候为目的而举办的活动。类似的派对本身并不罕见，但“G&amp;G”从会场演出到BMSG艺人及工作人员的待客之道，全部都被BMSG的风格所贯穿。虽然以商务关系为基础，但整个空间更充满了“非常开心”的氛围。SKY-HI为何举办这场派对？又为何能营造出这样的“非常开心”的空间？</strong></p><p>自BMSG成立以来已过去两年半，承蒙大家支持，如今不仅是在音乐与媒体领域，在各个领域中都有支持BE:FIRST以及我们这些SOLO艺人的人，也有对BMSG产生共鸣的人存在。尤其是在去年9月“BMSG FES”成功举办之后，这种情况进一步扩大了。单纯的“支持”已经令人感激，但我认为，今后需要进一步把大家作为“伙伴”卷入进来，一起前行。</p><p>不仅是音乐行业或演艺圈，我认为在1990年代、2000年代曾经存在的那种“令人兴奋的动能”，如今正在不断减弱。在这样的背景下，要让BE:FIRST、MAZZEL以及SOLO艺人们乘势而上，就必须让业内人士感受到“现在的BMSG很有势头”。</p><p>在新冠疫情持续期间，各公司都在自我克制举办这类邀请外部人士的活动，因此我觉得“现在正是机会”。毕竟比起景气低迷，大家更喜欢景气向好的氛围吧，所以也希望作为BMSG，把这种积极的氛围对外展现出来。</p><h3 id="主动享受其中的艺人们" tabindex="-1">主动享受其中的艺人们 <a class="header-anchor" href="#主动享受其中的艺人们" aria-label="Permalink to &quot;主动享受其中的艺人们&quot;">​</a></h3><p><strong>在入口处由SKY-HI本人迎接来宾，会场内不仅是工作人员，艺人们也主动向来宾致意与交流。在派对中段的Showcase环节中，以社长SKY-HI为首，甚至连还在训练生阶段的REIKO也登台进行了迷你Live表演。或许正因为SKY-HI既是社长也是艺人，艺人们也以BMSG一员的身份具备主人意识；即便是在聚集了商业人士的Showcase中，也毫不怯场地完成演出，这种氛围正是BMSG独有的。</strong></p><p>这一点，从好的意义上来说，完全就是公司的氛围所致。社长是我（艺人SKY-HI）这件事既有优点也有缺点，但像这样的场合不会让人感到恐惧，这是很大的优势。而让我再次感受到BMSG优点的是，艺人们也都非常主动地在享受其中。</p><p>从艺人的角度来看，在相关人士聚集的场合演出，往往会带有向观众致意、某种意义上的“应酬”性质。我自己也见过很多这样的场面，也多次站上过那样的舞台。所以我一边紧张地看着BMSG艺人的舞台，但他们真的表现得非常开心，甚至可以说是在这种派对上从未见过的开心状态，现场气氛也被带动得非常热烈。</p><p>该怎么说呢，大概是因为所有人都有一种“要一起创造快乐”的强烈氛围吧。我不想说、也没有说什么“今天很重要，要好好表现！”之类的话，但结果大家都呈现出了非常好的舞台。</p><p>第一个登台的是Core（Novel Core），真的非常出色。作为一名Rapper，需要具备“读懂空气”和“故意不读空气”这两种能力，而他在那个场合完美地兼顾了这两点。我把这点告诉他时，他说：“今天BMSG举办这样的派对，（Showcase的）第一个是我，那我就应该呈现这样的演出，嘿嘿（笑）。”真的很聪明，也很帅气，让人充满感激。REIKO也完成得非常出色。在面向业内人士的派对上表演其实并不轻松，尤其对一个还未出道的新人来说，紧张感一定很强，但他依然全力以赴地完成了演出，非常帅气。edhiii boi也全力以赴地完成了表演，虽然可能是第一次被很多人看到的舞台，但也从来宾那里收获了很多反馈。</p><p>反过来说，（Aile The）Shota在那种场合反而选择放松状态登台，这一点也非常精彩，并且以“LOVE”为主题，很好地为最后登场的我做了铺垫，形成了完美的流程。我当时就想着“那我也只能上了！”于是走上舞台。表演了《D.U.N.K.》，从舞台一侧跑到另一侧，结果回头一看，艺人们也都上了台，在我后面一起跳舞（笑）。真的非常开心，也非常感激，非常快乐，看着身后我甚至在想“这是什么神仙公司啊！”而这种氛围也比想象中更好地传达给了在场的各位来宾。</p><p>现在对于艺人来说，一个很好的状况是，我们已经创造出了许多“现场很开心”的成功体验。在“G&amp;G”中，也完全没有那种“这是公司的派对，必须严肃一点，否则会被骂”的氛围，大家都很放松。当然，从某种角度来说，严谨一些也会让人更安心，这也是今后的一个课题，但我现在非常强烈地感受到：当艺人能够自由成长时，在这样的场合也会自然发挥，从而让观众也能自在地享受其中。基于这一点，BMSG下一财年的商业主题定为“快乐”。</p><p>通过这次派对，我再次意识到，自己最重要的工作，果然还是让人觉得“很开心啊”“看起来很有趣啊”。</p><h3 id="正确地做梦-正确地努力···" tabindex="-1">正确地做梦，正确地努力··· <a class="header-anchor" href="#正确地做梦-正确地努力···" aria-label="Permalink to &quot;正确地做梦，正确地努力···&quot;">​</a></h3><p><strong>“Greeting&amp;Gathering”这个词本身并不常见，这个命名是由SKY-HI本人提出的（取自BMSG四个字母中的“G”）。正如字面意义，这是一场将分布在各行各业、支持BMSG的伙伴聚集在一起的活动。最后，他也谈到了自己是如何看待这些伙伴的。</strong></p><p>值得感激的是，无论是帮助BMSG的人，还是与我们一起合作的人，即便是大型企业的人员，也并不是以一种冷冰冰的商业关系在合作，而是以更有人情味的方式在一起工作。与其说是工作，不如说更像是“大家一起增加伙伴，一起努力”的感觉，甚至带有一点少年漫画的氛围。喜欢这种感觉的成年人其实很多，我自己也是其中之一，可以说是一种“《ONE PIECE》症候群”吧。虽然从常规角度来看，可能会觉得“都已经是大人了还说这种话”才是正常反应（笑），但我自己很喜欢这种少年漫画式的活法，也非常推荐。</p><p>正确地做梦，朝着它正确地努力，正确地增加伙伴，并且正确地实现它——这无论在商业意义上，还是在人生意义上，我都非常推荐。而对于那些对这种心态产生共鸣的人来说，就不仅仅是商业关系，而是可以作为“伙伴”一起工作。我也希望今后能够不断扩大这样的圈子。</p>',21)])])}const d=e(o,[["render",n]]);export{l as __pageData,d as default};
